router = APIRouter(prefix="/api", tags=["presenter"])

UI_PREVIEW_ROWS = 50
Scalar = (str, int, float, bool, type(None))

# Generic wrapper keys that get priority when two keys tie on array length.
# These are common "generic" wrapper names used across many APIs/ERPs.
# Domain-specific keys (customers, jobs, invoices, quotes, etc.) are auto-detected
# by _find_data_array() — no need to register them here.
_GENERIC_DATA_KEYS = frozenset(("data", "results", "items", "value", "records", "rows"))

# Keys that are clearly metadata, not the main data array — skip them during auto-detection.
_META_KEYS = frozenset((
    "success", "error", "errors", "message", "status", "code",
    "total", "total_fetched", "total_count", "count",
    "page", "pages", "pages_fetched", "page_size", "pageSize",
    "next", "previous", "cursor", "has_more",
    "formatted", "tool", "metadata", "meta", "warnings",
))


def _find_data_array(payload: Dict[str, Any]) -> Optional[str]:
    """Auto-detect which key in a dict-wrapper holds the main data array.

    Strategy:
      1. Skip keys that are known metadata (_META_KEYS).
      2. Among remaining keys whose value is a non-empty list, pick the one
         with the most items.  On ties, prefer _GENERIC_DATA_KEYS.
      3. If there's only one list-valued key (ignoring metadata), use it
         regardless of length — even a 1-element list is valid data.

    Returns the key name, or None if no suitable array is found.
    """
    candidates: List[Tuple[str, int]] = []   # (key, length)
    for k, v in payload.items():
        if k in _META_KEYS:
            continue
        if isinstance(v, list) and v:
            candidates.append((k, len(v)))

    if not candidates:
        return None

    # Single candidate — no ambiguity
    if len(candidates) == 1:
        return candidates[0][0]

    # Multiple candidates — pick longest; break ties by generic-key priority
    candidates.sort(key=lambda x: (x[1], x[0] in _GENERIC_DATA_KEYS), reverse=True)
    return candidates[0][0]

# ===================== Telemetry (in-memory) =====================
_stats_lock = threading.Lock()
_stats = {
    "hints_requested": 0,
    "hints_applied": 0,
    "hints_ignored": 0,
    "dropped_keys_total": 0,
    "columns_built_total": 0
}

def _stats_inc(key: str, amt: int = 1):
    with _stats_lock:
        _stats[key] = _stats.get(key, 0) + amt

def _telemetry_log(event: str, data: Dict[str, Any]):
    if PRESENTER_TELEMETRY_SINK == "console":
        try:
            print(f"[presenter][{event}] {json.dumps(data, ensure_ascii=False)}")
        except Exception:
            pass

@router.get("/presenter/stats")
def presenter_stats():
    with _stats_lock:
        return dict(_stats)

@router.post("/presenter/stats/reset")
def presenter_stats_reset():
    with _stats_lock:
        for k in _stats.keys():
            _stats[k] = 0
    return {"ok": True}

