    payload: Any
    hints: Optional[Dict[str, Any]] = None  # { llm_schema_hints?: bool, allow_llm?: bool }
    llm_fn: Optional[Any] = None  # Per-org LLM callable — passed from chat.py's _effective_llm_chat

