# ===================== CSV helper =====================
def _csv_blob_full(rows: List[Dict[str, Any]]) -> str:
    if not rows:
        return "data:text/csv;charset=utf-8,"
    cols: List[str] = []
    seen = set()
    for r in rows:
        if isinstance(r, dict):
            for k in r.keys():
                if k not in seen:
                    seen.add(k); cols.append(k)

    def esc(v: Any) -> str:
        s = "" if v is None else str(v)
        if any(c in s for c in [",", '"', "\n"]):
            s = '"' + s.replace('"','""') + '"'
        return s

    header = ",".join(cols)
    body = "\n".join(",".join(esc(r.get(c)) for c in cols) for r in rows)
    csv_text = header + "\n" + body
    return "data:text/csv;charset=utf-8," + quote(csv_text, safe=",")

# ===================== Excel helper =====================
def _xlsx_blob(rows: List[Dict[str, Any]]) -> str:
    """Build a base64 data-URL for an .xlsx file from a list of row dicts."""
    from openpyxl import Workbook
    from openpyxl.styles import Font, PatternFill, Alignment, Border, Side

    wb = Workbook()
    ws = wb.active
    ws.title = "Export"

    if not rows:
        buf = io.BytesIO()
        wb.save(buf)
        b64 = base64.b64encode(buf.getvalue()).decode()
        return f"data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64,{b64}"

    # Collect column keys in insertion order
    cols: List[str] = []
    seen = set()
    for r in rows:
        if isinstance(r, dict):
            for k in r.keys():
                if k not in seen:
                    seen.add(k); cols.append(k)

    # Header row styling
    header_font = Font(bold=True, color="FFFFFF", size=11)
    header_fill = PatternFill(start_color="4472C4", end_color="4472C4", fill_type="solid")
    header_align = Alignment(horizontal="center", vertical="center")
    thin_border = Border(
        bottom=Side(style="thin", color="B4C6E7"),
    )

    for ci, col_name in enumerate(cols, 1):
        cell = ws.cell(row=1, column=ci, value=_humanize_label(col_name))
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = header_align

    # Data rows
    alt_fill = PatternFill(start_color="D9E2F3", end_color="D9E2F3", fill_type="solid")
    for ri, row in enumerate(rows, 2):
        for ci, col_name in enumerate(cols, 1):
            cell = ws.cell(row=ri, column=ci, value=row.get(col_name, ""))
            cell.border = thin_border
            if ri % 2 == 0:
                cell.fill = alt_fill

    # Auto-fit column widths (approximate)
    for ci, col_name in enumerate(cols, 1):
        max_len = len(_humanize_label(col_name))
        for ri in range(2, min(len(rows) + 2, 52)):  # sample first 50 rows
            val = str(ws.cell(row=ri, column=ci).value or "")
            max_len = max(max_len, len(val))
        ws.column_dimensions[ws.cell(row=1, column=ci).column_letter].width = min(max_len + 3, 50)

    buf = io.BytesIO()
    wb.save(buf)
    b64 = base64.b64encode(buf.getvalue()).decode()
    return f"data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64,{b64}"

# ===================== Flattening (deep — all nested data merged) =====
# ALL nested data (objects, arrays of objects) is flattened into the
# main row with prefixed column names.  No sub-tables are created.
# This keeps every field from the API response visible in one table.
# =====================================================================
def _join(prefix: str, key: str) -> str:
    return key if not prefix else f"{prefix}_{key}"


def _deep_flatten_dict(obj: Dict[str, Any], prefix: str) -> Dict[str, Any]:
    """Recursively flatten a dict.  Nested dicts get prefixed keys.
    Lists of dicts get their values joined per-field."""
    out: Dict[str, Any] = {}
    for k, v in obj.items():
        key = _join(prefix, k)
        if isinstance(v, dict):
            out.update(_deep_flatten_dict(v, key))
        elif isinstance(v, list):
            out.update(_deep_flatten_list(v, key))
        else:
            out[key] = clean_html(v) if isinstance(v, str) else v
    return out


def _deep_flatten_list(lst: list, key: str) -> Dict[str, Any]:
    """Flatten a list value into columns.
    - Empty list        → key: ""
    - Scalars           → key: comma-joined string
    - List of dicts     → flatten each item, then join values per column
    """
    out: Dict[str, Any] = {}
    if not lst:
        out[key] = ""
        return out
    # All scalars — join
    if all(isinstance(x, Scalar) for x in lst):
        out[key] = ", ".join(str(x) for x in lst)
        return out
    # All dicts — flatten each, then merge per-field
    if all(isinstance(x, dict) for x in lst):
        flat_items = [_deep_flatten_dict(item, key) for item in lst]
        # Collect all keys in order
        all_keys: list[str] = []
        seen: set[str] = set()
        for fi in flat_items:
            for fk in fi.keys():
                if fk not in seen:
                    seen.add(fk)
                    all_keys.append(fk)
        # For single-item lists, use values directly; for multi-item, join
        if len(flat_items) == 1:
            out.update(flat_items[0])
        else:
            for fk in all_keys:
                vals = [fi.get(fk) for fi in flat_items]
                # Filter None and join as comma-separated
                str_vals = [str(v) for v in vals if v is not None]
                out[fk] = ", ".join(str_vals) if str_vals else ""
        return out
    # Mixed types — JSON dump
    out[key] = json.dumps(lst, ensure_ascii=False)
    return out


def _flatten_row(item: Any) -> Tuple[Dict[str, Any], Dict[str, List]]:
    """Return (flat_row, empty_nested_dict).
    All nested data is now flattened into the main row — no sub-tables."""
    nested: Dict[str, List] = {}   # always empty now
    if isinstance(item, dict):
        return _deep_flatten_dict(item, ""), nested
    if isinstance(item, list):
        return _deep_flatten_list(item, "value"), nested
    return {"value": item}, nested


def _flatten_top_level(payload: Any) -> Tuple[List[Dict[str, Any]], List[str], Dict[str, List]]:
    """Returns (rows, columns, all_nested).
    *all_nested* aggregates every nested array across all rows so the
    envelope builder can create sub-table blocks for them."""
    rows: List[Dict[str, Any]] = []
    all_nested: Dict[str, List] = {}

    def _add(item):
        flat, nested = _flatten_row(item)
        rows.append(flat)
        for k, v in nested.items():
            all_nested.setdefault(k, []).extend(v)

    if isinstance(payload, list):
        for it in payload:
            _add(it)
    elif isinstance(payload, dict):
        # Auto-detect which key holds the main data array (ERP-agnostic)
        data_key = _find_data_array(payload)
        if data_key is not None:
            for it in payload[data_key]:
                _add(it)
        else:
            _add(payload)
    else:
        _add(payload)

    cols: List[str] = []
    seen = set()
    for r in rows:
        for k in r.keys():
            if k not in seen:
                seen.add(k); cols.append(k)
    return rows, cols, all_nested

# ===================== LLM helpers =====================
def _first_json_obj(text: str) -> Optional[Dict[str, Any]]:
    m = re.search(r"\{[\s\S]*\}", text)
    if not m:
        return None
    try:
        return json.loads(m.group(0))
    except Exception:
        return None


def _llm_json(
    system: str,
    user: str,
    temperature: float = 0.0,
    llm_fn: Optional[Callable] = None,
) -> Optional[Dict[str, Any]]:
    """
    Send system + user prompt to the LLM and parse a JSON object.
    Uses per-org llm_fn when provided, falls back to global llm_chat.
    """
    fn = llm_fn or llm_chat
    try:
        messages = [
            {"role": "system", "content": system},
            {"role": "user", "content": user},
        ]
        txt = fn(
            messages,
            response_format={"type": "json_object"},
            temperature=temperature,
            sanitize=False,   # data is already sanitized by callers
        )
        txt = (txt or "").strip()
        print(f"[presenter][llm][raw_response]", repr(txt[:500]))

        # Try direct JSON parse
        try:
            data = json.loads(txt)
            if isinstance(data, dict):
                return data
        except json.JSONDecodeError as e:
            print("[presenter][llm][parse][json_error]", str(e))

            # Try cleaning markdown fences
            try:
                cleaned = re.sub(r'^```(?:json)?\s*|\s*```$', '', txt, flags=re.MULTILINE).strip()
                data = json.loads(cleaned)
                if isinstance(data, dict):
                    print("[presenter][llm][parse] Succeeded after cleaning markdown")
                    return data
            except json.JSONDecodeError:
                pass

            # Final fallback: extract first JSON object
            data = _first_json_obj(txt)
            if data:
                print("[presenter][llm][parse] Succeeded with regex extraction")
                return data

        if data is None:
            print("[presenter][llm][parse] No valid JSON object found")
        return data

    except Exception as e:
        print("[presenter][llm][error]", str(e))
        return None


