SCHEMA_SYS = """You are a column schema optimizer for table displays.

INPUT:
You will receive a JSON object with these keys:
- "question": the user's original question (string). Use this to decide which columns are relevant.
- "columns": a list of column names from the data.
- "sub_tables": (optional) a list of names of nested sub-tables extracted from the data.

YOUR TASK:
Analyze the column names IN THE CONTEXT OF the user's question.
Columns that are clearly irrelevant to what the user asked should be hidden.
Columns that are directly relevant should be placed first.

For example:
- If the user asks about "profitability" or "financials", prioritize cost/profit/margin fields.
  Hide unrelated metadata like custom fields, tags, HTML notes.
- If the user asks about "job details" or "overview", keep general job info visible.
- If the user asks about "schedule" or "dates", prioritize date and time fields.
- When in doubt, keep the column visible rather than hiding it.

OUTPUT FORMAT (VERY IMPORTANT):
Return exactly ONE JSON object with this structure:

{
  "column_reorder": [<list of column names in preferred order>],
  "column_labels": {<original_name>: <readable_label>, ...},
  "hide_columns": [<list of column names to hide>],
  "hide_sub_tables": [<list of sub-table names to hide entirely>]
}

RULES:
1. column_reorder: Put the columns most relevant to the user's question first.
   Then other useful business columns. Technical/internal columns last (or hidden).
2. column_labels: Convert technical names to readable labels
   - Example: "DateIssued" → "Date Issued"
   - Example: "TotalAmount" → "Total Amount"
   - Example: "job_id" → "Job ID"
3. hide_columns: Hide columns irrelevant to the user's question.
   - Hide raw nested object counts (e.g. fields showing "5 items")
   - Hide HTML content fields, internal tags, audit trails
   - Hide duplicate or redundant information
   - Keep key identifiers and fields relevant to the question
4. hide_sub_tables: List any sub-table names that are irrelevant to the question.
   - For example, if the user asked about profitability, hide "Custom Fields" and "Tags".
   - If unsure, do NOT include the sub-table in this list (keep it visible).

Do NOT wrap in markdown or code fences. Return pure JSON only.
"""


def _llm_summary(question: str, payload: Any, hints: Dict[str, Any], llm_fn: Optional[Callable] = None) -> Optional[str]:
    """
    Generate a business-friendly summary using the shared LLM gateway.
    PII is stripped from the payload before it reaches the LLM.

    When ``hints["llm_draft"]`` is present the LLM already produced a
    conversational answer during streaming.  We pass that draft (instead
    of the heavy JSON payload) so the LLM only needs to *rewrite* it
    with the personality voice rules — much faster and cheaper.
    """
    try:
        draft: Optional[str] = (hints or {}).get("llm_draft")

        if draft:
            # ── DRAFT PATH: rewrite the streamed response with personality ──
            safe_payload = sanitize_for_llm(payload)
            record_count = None
            if isinstance(safe_payload, list):
                record_count = len(safe_payload)
            elif isinstance(safe_payload, dict):
                dk = _find_data_array(safe_payload)
                if dk:
                    record_count = len(safe_payload[dk])

            user_obj: dict = {
                "question": question,
                "draft": draft,
                "hints": {k: v for k, v in (hints or {}).items() if k != "llm_draft"},
            }
            if record_count is not None:
                user_obj["record_count"] = record_count
                user_obj["IMPORTANT"] = (
                    f"The payload contains exactly {record_count} record(s). "
                    f"Your summary MUST acknowledge these {record_count} record(s). "
                    f"Do NOT say 'no records found' or 'none found' if record_count > 0."
                )
            user = json.dumps(user_obj, ensure_ascii=False, default=str)
            print(f"[presenter] DRAFT PATH — rewriting {len(draft)} char draft with personality")
        else:
            # ── FULL PATH: summarise from raw payload ──
            safe_payload = sanitize_for_llm(payload)

            record_count = None
            _data_key = None
            if isinstance(safe_payload, list):
                record_count = len(safe_payload)
            elif isinstance(safe_payload, dict):
                _data_key = _find_data_array(safe_payload)
                if _data_key:
                    record_count = len(safe_payload[_data_key])

            sample = safe_payload
            if isinstance(safe_payload, list) and len(safe_payload) > 120:
                sample = safe_payload[:60] + safe_payload[-60:]
            elif _data_key and record_count and record_count > 120:
                sample = {**safe_payload, _data_key: safe_payload[_data_key][:60] + safe_payload[_data_key][-60:]}

            user_obj = {"question": question, "payload": sample, "hints": hints or {}}
            if record_count is not None:
                user_obj["record_count"] = record_count
                user_obj["IMPORTANT"] = (
                    f"The payload contains exactly {record_count} record(s). "
                    f"Your summary MUST acknowledge these {record_count} record(s). "
                    f"Do NOT say 'no records found' or 'none found' if record_count > 0."
                )
            user = json.dumps(user_obj, ensure_ascii=False, default=str)

        data = _llm_json(_get_summary_sys(), user, temperature=_PERSONALITY_TEMP, llm_fn=llm_fn)
        if not data:
            print("[presenter][llm][summary] _llm_json returned None")
            return None

        s = data.get("summary")
        if not isinstance(s, str):
            print("[presenter][llm][summary] 'summary' key missing or not a string:", data)
            return None

        s_clean = s.strip()
        if not s_clean:
            print("[presenter][llm][summary] summary string is empty/whitespace")
            return None
        return s_clean

    except Exception as e:
        print("[presenter][llm][summary][error]", str(e))
        return None


_schema_hints_cache: Dict[str, Dict[str, Any]] = {}
_SCHEMA_CACHE_MAX = 200  # max entries before clearing oldest half


def _llm_schema_hints(columns: List[str], question: str = "",
                      sub_table_names: Optional[List[str]] = None,
                      llm_fn: Optional[Callable] = None) -> Dict[str, Any]:
    """
    Ask the LLM about column layout.  Only column NAMES and the user's
    question are sent — no row data, no financial values.

    Results are cached by (sorted columns, sub_table_names) — the same
    column set always gets the same layout hints regardless of question.
    """
    # Build cache key from column set + sub-tables (question excluded on purpose:
    # column layout is determined by schema, not by the specific question).
    cache_key = "|".join(sorted(columns))
    if sub_table_names:
        cache_key += "||" + "|".join(sorted(sub_table_names))

    cached = _schema_hints_cache.get(cache_key)
    if cached is not None:
        print(f"[presenter][schema] Cache HIT ({len(_schema_hints_cache)} entries)")
        return cached

    try:
        payload: Dict[str, Any] = {"question": question, "columns": columns}
        if sub_table_names:
            payload["sub_tables"] = sub_table_names
        user = json.dumps(payload, ensure_ascii=False)
        data = _llm_json(SCHEMA_SYS, user, llm_fn=llm_fn) or {}
        result = {
            "column_reorder":  data.get("column_reorder") or [],
            "column_labels":   data.get("column_labels") or {},
            "hide_columns":    data.get("hide_columns") or [],
            "hide_sub_tables": data.get("hide_sub_tables") or []
        }

        # Evict oldest half when cache is full
        if len(_schema_hints_cache) >= _SCHEMA_CACHE_MAX:
            keys = list(_schema_hints_cache.keys())
            for k in keys[:len(keys) // 2]:
                _schema_hints_cache.pop(k, None)

        _schema_hints_cache[cache_key] = result
        print(f"[presenter][schema] Cache MISS → stored ({len(_schema_hints_cache)} entries)")
        return result
    except Exception as e:
        print("[presenter][llm][schema][error]", str(e))
        return {"column_reorder": [], "column_labels": {}, "hide_columns": [],
                "hide_sub_tables": []}


# ===================== Apply schema hints safely =====================
def _apply_schema_hints(columns: List[str],
                        rows: List[Dict[str, Any]],
                        hints: Dict[str, Any]) -> Tuple[List[Dict[str,str]], List[Dict[str,Any]], Dict[str, Any]]:
    existing = set(columns)
    dropped = {"reorder_not_found": [], "labels_not_found": [], "hide_not_found": []}

    reorder = [c for c in hints.get("column_reorder", []) if c in existing]
    rest = [c for c in columns if c not in reorder]
    ordered = reorder + rest

    hide = [c for c in hints.get("hide_columns", []) if c in existing]
    hidden = set(hide)
    visible = [c for c in ordered if c not in hidden]

    labels_src = hints.get("column_labels", {}) or {}
    labels: Dict[str, str] = {}
    for k, v in labels_src.items():
        if k in existing and isinstance(v, str) and v.strip():
            labels[k] = v.strip()
        else:
            dropped["labels_not_found"].append(k)

    for c in hints.get("column_reorder", []):
        if c not in existing: dropped["reorder_not_found"].append(c)
    for c in hints.get("hide_columns", []):
        if c not in existing: dropped["hide_not_found"].append(c)

    _stats_inc("dropped_keys_total", sum(len(v) for v in dropped.values()))

    cols_spec = [{"key": c, "label": labels.get(c, c)} for c in visible]
    applied = any([reorder, hide, labels])
    if applied:
        _stats_inc("hints_applied")
    else:
        _stats_inc("hints_ignored")

    return cols_spec, rows, {"applied": applied, "dropped": dropped}

# ===================== Envelopes =====================
def _fallback_summary(payload: Any) -> str:
    if isinstance(payload, list): return f"{len(payload)} records."
    if isinstance(payload, dict):
        # Auto-detect dict-wrapped arrays
        data_key = _find_data_array(payload)
        if data_key:
            return f"{len(payload[data_key])} records."
        nm = payload.get("CompanyName") or payload.get("Name") or ""
        amt = payload.get("AmountOwing") or payload.get("balance")
        bits = []
        if nm: bits.append(str(nm).strip())
        if amt is not None: bits.append(f"Owes {amt}")
        return " • ".join(bits) if bits else "1 record."
    return "Response."

def _humanize_label(key: str) -> str:
    """Turn 'CostCentre_SomeThing' into 'Cost Centre Some Thing'."""
    # Split on underscores first
    parts = key.split("_")
    # Then split camelCase within each part
    expanded = []
    for part in parts:
        expanded.append(re.sub(r'(?<=[a-z])(?=[A-Z])', ' ', part))
    return " ".join(expanded).strip()


def _build_sub_table_block(label: str, items: List[Dict[str, Any]]) -> Dict[str, Any]:
    """Build a table block for a nested array (e.g. CostCentres)."""
    sub_rows: List[Dict[str, Any]] = []
    for item in items:
        flat, _ = _flatten_row(item)          # flatten one level (ignore deeper nesting)
        sub_rows.append(flat)

    sub_cols: List[str] = []
    seen = set()
    for r in sub_rows:
        for k in r.keys():
            if k not in seen:
                seen.add(k); sub_cols.append(k)

    cols_spec = [{"key": c, "label": _humanize_label(c)} for c in sub_cols]
    shown = min(UI_PREVIEW_ROWS, len(sub_rows))

    return {
        "type": "table",
        "title": _humanize_label(label),
        "spec": {
            "columns": cols_spec,
            "rows": sub_rows[:shown],
            "preview": {"shown": shown, "total": len(sub_rows)},
            "downloads": [
                {"type": "csv", "blob": _csv_blob_full(sub_rows)},
                {"type": "json", "blob": "data:application/json," + quote(json.dumps(items, default=str))},
                {"type": "xlsx", "blob": _xlsx_blob(sub_rows)},
            ],
            "note": (f"Showing {shown} of {len(sub_rows)}." if len(sub_rows) > shown else None),
        },
    }


def _envelope_from_rows(rows: List[Dict[str, Any]], summary: str, original_payload: Any,
                        enable_hints: bool,
                        all_nested: Optional[Dict[str, List]] = None,
                        question: str = "",
                        precomputed_hints: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    cols: List[str] = []
    seen = set()
    for r in rows:
        for k in r.keys():
            if k not in seen:
                seen.add(k); cols.append(k)

    shown = min(UI_PREVIEW_ROWS, len(rows))

    sub_table_names = list(all_nested.keys()) if all_nested else []

    if precomputed_hints is not None:
        # Use pre-fetched hints (from parallel execution in present())
        _stats_inc("hints_requested")
        cols_spec, rows_final, tele = _apply_schema_hints(cols, rows, precomputed_hints)
        hidden_subs = set(precomputed_hints.get("hide_sub_tables") or [])
    elif enable_hints and rows:
        _stats_inc("hints_requested")
        hints = _llm_schema_hints(cols, question=question,
                                  sub_table_names=sub_table_names or None)
        cols_spec, rows_final, tele = _apply_schema_hints(cols, rows, hints)
        hidden_subs = set(hints.get("hide_sub_tables") or [])
    else:
        cols_spec = [{"key": c, "label": _humanize_label(c)} for c in cols]
        rows_final = rows
        tele = {"applied": False, "dropped": {}}
        hidden_subs = set()

    _stats_inc("columns_built_total", len(cols_spec))

    main_block = {
        "type": "table",
        "title": "Results" if len(rows) > 1 else "Record",
        "spec": {
            "columns": cols_spec,
            "rows": rows_final[:shown],
            "preview": {"shown": shown, "total": len(rows_final)},
            "downloads": [
                {"type":"csv","blob": _csv_blob_full(rows_final)},
                {"type":"json","blob":"data:application/json," + quote(json.dumps(original_payload, default=str))},
                {"type":"xlsx","blob": _xlsx_blob(rows_final)}
            ],
            "note": (f"Showing {shown} of {len(rows_final)}. Download CSV/Excel for all rows."
                     if len(rows_final) > shown else None)
        },
        "telemetry": tele
    }

    blocks = [main_block]

    # Add sub-table blocks, skipping any the LLM marked as irrelevant
    if all_nested:
        for key, items in all_nested.items():
            if items and key not in hidden_subs:
                blocks.append(_build_sub_table_block(key, items))

    env = {
        "title": "Results",
        "summary": summary,
        "blocks": blocks,
    }
    return env

# ===================== Route =====================
@router.post("/present", response_model=PresentResponse)
def present(req: PresentRequest):
    payload = req.payload
    hints = req.hints or {}
    llm_fn = req.llm_fn or None  # Per-org LLM fn from chat.py; None → falls back to global llm_chat

    # Log incoming payload
    try:
        safe_log = sanitize_for_llm(payload)
        print("\n\n=== PAYLOAD FROM AGENT (PII-safe) ===")
        print(json.dumps(safe_log, ensure_ascii=False, indent=2, default=str)[:3000])
        print("=== END PAYLOAD ===\n\n")
    except Exception as e:
        print("[presenter][payload_in][error_serializing]", str(e))

    try:
        # 1) Build table rows LOCALLY — no LLM, no data leak
        rows, _, all_nested = _flatten_top_level(payload)

        # 2) Determine schema hints toggle
        enable_hints = hints.get("llm_schema_hints")
        if enable_hints is None:
            enable_hints = PRESENTER_USE_LLM_SCHEMA_HINTS

        # 3) LLM calls — parallel when both summary + schema hints are needed
        #    llm_draft (if present in hints) lets _llm_summary() rewrite the
        #    streamed text with personality instead of analysing raw JSON.
        if enable_hints and rows:
            from concurrent.futures import ThreadPoolExecutor
            cols = [c for c in rows[0].keys()] if rows else []
            sub_table_names = list(all_nested.keys()) if all_nested else []
            with ThreadPoolExecutor(max_workers=2) as pool:
                summary_future = pool.submit(_llm_summary, req.question, payload, hints, llm_fn)
                hints_future = pool.submit(_llm_schema_hints, cols, req.question, sub_table_names or None, llm_fn)
                summary = summary_future.result() or _fallback_summary(payload)
                schema_hints = hints_future.result()
            env = _envelope_from_rows(rows, summary, payload, False, all_nested,
                                      question=req.question, precomputed_hints=schema_hints)
        else:
            summary = _llm_summary(req.question, payload, hints, llm_fn) or _fallback_summary(payload)
            env = _envelope_from_rows(rows, summary, payload, False, all_nested,
                                      question=req.question)

        # 5) Telemetry + logging
        _telemetry_log("render", {
            "enable_hints": bool(enable_hints),
            "rows": len(rows),
            "cols": len(env["blocks"][0]["spec"]["columns"]),
            "llm_provider": LLM_PROVIDER,
            "llm_model": LLM_MODEL,
        })
        print("[presenter][summary]", (summary or "").strip()[:200])

        return PresentResponse(envelope=env, telemetry={
            "model": f"{LLM_PROVIDER}:{LLM_MODEL}",
            "env_llm_schema_hints": PRESENTER_USE_LLM_SCHEMA_HINTS
        })

    except Exception as e:
        _telemetry_log("error", {"error": str(e)})
        fallback = {
            "summary": "Response.",
            "blocks": [{
                "type": "json",
                "title": "Raw JSON",
                "spec": {
                    "json": payload,
                    "downloads": [{
                        "type": "json",
                        "blob": "data:application/json," + quote(json.dumps(payload, default=str))
                    }]
                }
            }]
        }
        return PresentResponse(
            envelope=fallback,
            telemetry={"error": str(e), "fallback": True, "model": f"{LLM_PROVIDER}:{LLM_MODEL}"}
        )
